import{_ as a,o as t,c as o,ae as n}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"GTM Overview","description":"","frontmatter":{"title":"GTM Overview","slug":"google-tag-manager"},"headers":[],"relativePath":"developer-hub/google-tag-manager.md","filePath":"developer-hub/google-tag-manager.md"}'),r={name:"developer-hub/google-tag-manager.md"};function s(i,e,c,l,g,d){return t(),o("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Using Google Tag Manager (GTM) gives you a way to trigger actions that update your data in Branch.</p><p>These actions include logging events and setting user identities. To do this, GTM calls various Branch functions included in your SDK integration.</p><p>Which functions are called and when depends on how you configure your tags and triggers in GTM.</p><h2 id="guides" tabindex="-1">Guides <a class="header-anchor" href="#guides" aria-label="Permalink to &quot;Guides&quot;">​</a></h2><p>To learn more about using GTM with Branch, visit our guides:</p><p><a href="./gtm-web.html">Web</a></p><p><a href="./gtm-ios.html">iOS</a></p><p><a href="./gtm-android.html">Android</a></p><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><blockquote><p><strong>Do I need to create multiple tags in GTM?</strong></p><p>You may need to create multiple tags in GTM if you want to track more than one type of Branch Event. Each type of event you want to track will have a different tag.</p></blockquote><blockquote><p><strong>Do I need to create multiple custom classes extending</strong> <code>GoogleTagManager</code> <strong>in my code?</strong></p><p>No, you will create one custom class. All the tags you create in GTM will reference the same class path.</p></blockquote><blockquote><p><strong>If I am already using a custom class for</strong> <code>GoogleTagManager</code><strong>, can I use the same one for Branch?</strong></p><p>Yes. You can leverage your existing custom class to track Branch Events. However you may decide you want to use a separate class code readability, maintainability, and debugging.</p></blockquote><blockquote><p><strong>How do I detect which event to trigger from the</strong> <code>execute()</code> <strong>callback within my custom class?</strong></p><p>You can pass a variable denoting the event type. This way, you can trigger Standard and Custom Branch Events accordingly in the <code>execute()</code> function&#39;s callback.</p></blockquote>',14)])])}const p=a(r,[["render",s]]);export{h as __pageData,p as default};
